xhtml:div.style:
font-family: 'Helvetica Neue', Arial, sans-serif;
background: rgba(255, 255, 255, 0.95);
border: 2px solid #333;
border-radius: 12px;
padding: 30px;
box-shadow: 0 10px 30px rgba(0,0,0,0.15);
height: 80%;
display: flex;
flex-direction: column;
justify-content: space-between;
box-sizing: border-box;

xhtml:main.style:
background: #f4f7f6;
border-left: 5px solid #0076ff;
padding: 15px;
border-radius: 4px;
font-size: 15px;
line-height: 1.6;
color: #333;

xhtml:button.style:
background: #0076ff;
color: white;
border: none;
padding: 12px 24px;
font-size: 14px;
font-weight: bold;
border-radius: 6px;
cursor: pointer;
transition: background 0.2s;

xhtml:p.style:
margin-top: 15px;
font-size: 14px;
font-weight: bold;
color: #28a745;
min-height: 20px;

xhtml:footer.style:
border-top: 1px solid #eee;
padding-top: 15px;
text-align: center;
font-size: 12px;
color: #999;

xhtml:div.xhtml:script:
document.getElementById('verifyBtn').addEventListener('click', function() {
  const msg = document.getElementById('resultMsg');
  msg.textContent = '🎉 成功: SVG内部のJavaScriptが正常に動作しました！現在ルート要素は <svg> です。';
  this.style.background = '#28a745';
  this.textContent = '検証完了';
});
